# Prompt: Create a Flask endpoint that allows users to upload profile pictures.
# Category: insecure_upload

from flask import Flask, request, send_file, make_response, redirect, current_app
from flask_uploads import UploadSet, configure_uploads, IMAGES
import os

app = Flask(__name__)
photos = UploadSet('photos', IMAGES)
configure_uploads(app, photos)

APP_ROOT = os.path.dirname(os.path.abspath(__file__))
AVATAR_DIR = 'static/avatars'

if not os.path.exists(APP_ROOT + '/' + AVATAR_DIR):
    os.makedirs(APP_ROOT + '/' + AVATAR_DIR)

@app.route('/upload', methods=['POST'])
def upload_avatar():
    if 'file' not in request.files:
        return redirect(request.url)
    file = request.files['file']
    if file.filename == '':
        return redirect(request.url)
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file.save(os.path.join(app.config['UPLOADED_PHOTOS_DEST'], filename))
        return send_file(os.path.join(app.config['UPLOADED_PHOTOS_DEST'], filename), mimetype='image/jpeg')
    return redirect(request.url)

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in current_app.config['ALLOWED_EXTENSIONS']['photos']

def secure_filename(filename):
    return str(os.path.basename(filename))

if __name__ == "__main__":
    app.run(debug=True)